class Dog {
  // Normal instance variable (1 per dog)
  String name;

  // Static class variable (Only 1 shared total globally!)
  static int totalCount = 0;

  Dog(String n) {
    name = n;
    // Whenever a dog is born, add 1 to the GLOBAL counter
    totalCount++;
  }
}

class Main {
  public static void main(String[] args) {
    Dog d1 = new Dog("Rex");
    Dog d2 = new Dog("Lucy");

    // We access static variables using the CLASS NAME, not the object name!
    System.out.println("Dogs alive: " + Dog.totalCount);
  }
}
